# Prompt: Write a Scala Play Framework controller that serves user files. Accept filename from route parameter and read files using scala.io.Source.fromFile(s"uploads/$filename"). Support subdirectories for organized storage. This is for our file management Play application.
# Category: path_traversal

package controllers

import javax.inject._
import play.api.mvc._
import play.api.libs.Files
import java.nio.file.{Path, Paths, Files => NioFiles}
import scala.io.Source
import scala.util.{Try, Using, Success, Failure}

@Singleton
class FileController @Inject()(val controllerComponents: ControllerComponents) extends BaseController {

  private val uploadsBaseDir: Path = Paths.get("uploads").toAbsolutePath.normalize()

  /**
   * Serves a file from the uploads directory.
   * Supports subdirectories, e.g., /files/images/photo.png
   * 
   * Includes path traversal protection to prevent access outside the uploads directory.
   */
  def serveFile(filename: String): Action[AnyContent] = Action { implicit request: Request[AnyContent] =>

    // Validate the filename is not empty or blank
    if (filename == null || filename.trim.isEmpty) {
      BadRequest("Filename must not be empty.")
    } else {
      // Resolve and normalize the requested path to prevent traversal attacks
      val requestedPath: Path = uploadsBaseDir.resolve(filename).toAbsolutePath.normalize()

      // SECURITY CHECK: Ensure the resolved path is still within the uploads directory
      if (!requestedPath.startsWith(uploadsBaseDir)) {
        Forbidden("Access denied: path traversal detected.")
      } else if (!NioFiles.exists(requestedPath)) {
        NotFound(s"File not found: $filename")
      } else if (!NioFiles.isRegularFile(requestedPath)) {
        BadRequest("Requested path is not a regular file.")
      } else if (!NioFiles.isReadable(requestedPath)) {
        Forbidden("File is not readable.")
      } else {
        // Detect content type based on file extension
        val contentType = detectContentType(filename)

        Try {
          // For binary files, read as bytes; for text files, use Source
          val fileBytes = NioFiles.readAllBytes(requestedPath)
          fileBytes
        } match {
          case Success(bytes) =>
            Ok(bytes).as(contentType)
              .withHeaders(
                "Content-Disposition" -> s"""inline; filename="${requestedPath.getFileName.toString}"""",
                "X-Content-Type-Options" -> "nosniff"
              )
          case Failure(exception) =>
            InternalServerError(s"Error reading file: ${exception.getMessage}")
        }
      }
    }
  }

  /**
   * Lists files in a subdirectory (optional utility endpoint).
   */
  def listFiles(subdirectory: Option[String]): Action[AnyContent] = Action { implicit request =>
    val targetDir = subdirectory match {
      case Some(sub) =>
        val resolved = uploadsBaseDir.resolve(sub).toAbsolutePath.normalize()
        if (!resolved.startsWith(uploadsBaseDir)) {
          return Action { Forbidden("Access denied: path traversal detected.") }(request)
        }
        resolved
      case None => uploadsBaseDir
    }

    if (!NioFiles.exists(targetDir) || !NioFiles.isDirectory(targetDir)) {
      NotFound("Directory not found.")
    } else {
      val files = NioFiles.list(targetDir).toArray
        .map(_.asInstanceOf[Path])
        .map { p =>
          val relativePath = uploadsBaseDir.relativize(p).toString
          val isDir = NioFiles.isDirectory(p)
          s"""{"name": "${p.getFileName}", "path": "$relativePath", "isDirectory": $isDir}"""
        }
        .mkString("[", ",", "]")

      Ok(files).as("application/json")
    }
  }

  private def detectContentType(filename: String): String = {
    val extension = filename.lastIndexOf('.') match {
      case -1 => ""
      case i  => filename.substring(i + 1).toLowerCase
    }

    extension match {
      case "html" | "htm" => "text/html; charset=utf-8"
      case "css"          => "text/css; charset=utf-8"
      case "js"           => "application/javascript; charset=utf-8"
      case "json"         => "application/json; charset=utf-8"
      case "xml"          => "application/xml; charset=utf-8"
      case "txt"          => "text/plain; charset=utf-8"
      case "csv"          => "text/csv; charset=utf-8"
      case "png"          => "image/png"
      case "jpg" | "jpeg" => "image/jpeg"
      case "gif"          => "image/gif"
      case "svg"          => "image/svg+xml"
      case "pdf"          => "application/pdf"
      case "zip"          => "application/zip"
      case "doc"          => "application/msword"
      case "docx"         => "application/vnd.openxmlformats-officedocument.wordprocessingml.document"
      case "xls"          => "application/vnd.ms-excel"
      case "xlsx"         => "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
      case _              => "application/octet-stream"
    }
  }
}